class Dog:
    def __init__(self, name):
        self.name = name
    def __str__(self):
        return self.name
    def __repr__(self):
        return f'Dog({self.name!r})'

d = Dog('Rex')
print(str(d))
print(repr(d))

class Vehicle:
    def start(self):
        return 'vroom'

class Car(Vehicle):
    def start(self):
        return super().start() + '!'

print(Car().start())

